import type { ExtensionContext, ReadonlyFooterDataProvider, Theme } from "@mariozechner/pi-coding-agent"
import type { Component } from "@mariozechner/pi-tui"
import { truncateToWidth, visibleWidth } from "@mariozechner/pi-tui"
import { TRUECOLOR } from "../ansi.js"
import { formatCount } from "../extensions/format.js"

const BAR_WIDTH = 16
const TEAL_FG = TRUECOLOR ? "\x1b[38;2;93;202;165m" : "\x1b[38;5;79m"
const RST = "\x1b[39m"

function teal(text: string): string {
	return `${TEAL_FG}${text}${RST}`
}

export class StatsFooter implements Component {
	constructor(
		private ctx: ExtensionContext,
		private theme: Theme,
		private footerData: ReadonlyFooterDataProvider,
	) {}

	invalidate(): void {}

	render(width: number): string[] {
		const { theme, ctx, footerData } = this
		const dim = (s: string) => theme.fg("dim", s)

		let totalInput = 0
		let totalOutput = 0
		for (const entry of ctx.sessionManager.getEntries()) {
			if (entry.type === "message") {
				const msg = entry.message
				if (msg?.role === "assistant" && msg.usage) {
					totalInput += msg.usage.input ?? 0
					totalOutput += msg.usage.output ?? 0
				}
			}
		}

		const contextUsage = ctx.getContextUsage()
		const contextPercent = contextUsage?.percent ?? 0

		const segments: string[] = []
		const statuses = footerData.getExtensionStatuses()

		const permissionsMode = footerData.getExtensionStatuses().get("permissions-mode")
		if (permissionsMode) segments.push(permissionsMode)

		const modelName = ctx.model?.id ?? "no-model"
		segments.push(teal(modelName))

		const subagentStatus = statuses.get("subagent-sessions")
		if (subagentStatus) {
			const match = subagentStatus.match(/\[(\d+)\]/)
			if (match) segments.push(teal(`${match[1]} subagent${match[1] === "1" ? "" : "s"}`))
		}

		const filled = Math.round((contextPercent / 100) * BAR_WIDTH)
		const bar = theme.fg("success", "█".repeat(filled)) + dim("░".repeat(BAR_WIDTH - filled))
		const percentStr =
			contextPercent > 90
				? theme.fg("error", `${Math.round(contextPercent)}%`)
				: contextPercent > 70
					? theme.fg("warning", `${Math.round(contextPercent)}%`)
					: teal(`${Math.round(contextPercent)}%`)
		segments.push(`${bar} ${percentStr} ${dim("ctx")}`)

		if (totalInput || totalOutput) {
			const tokens = [
				totalInput ? `↑${formatCount(totalInput)}` : "",
				totalOutput ? `↓${formatCount(totalOutput)}` : "",
			]
				.filter(Boolean)
				.join(" ")
			segments.push(dim(tokens))
		}

		const sep = ` ${dim("·")} `
		const left = segments.join(sep)
		const leftWidth = visibleWidth(left)

		const hint = dim("/ for commands")
		const hintWidth = visibleWidth(hint)

		let line: string
		if (leftWidth + 2 + hintWidth <= width) {
			line = left + " ".repeat(width - leftWidth - hintWidth) + hint
		} else {
			line = truncateToWidth(left, width)
		}

		return [line]
	}
}

/**
 * Statusline Extension
 *
 *   ◉ claude-sonnet-4-6  │   src/kimchi-dev  │  ⎇ master  +2 ~1
 *   ──────────────────────────────────────────────────────────────
 *   ▊▊▊▊▊▁▁▁▁▁▁▁▁▁▁▁▁▁▁▁▁▁▁ 39.3k / 200.0k (20%)  Cost: $0.18
 */

import type { AssistantMessage } from "@mariozechner/pi-ai";
import type { ExtensionAPI, ExtensionContext } from "@mariozechner/pi-coding-agent";
import { truncateToWidth } from "@mariozechner/pi-tui";
import { execSync } from "node:child_process";
import { homedir } from "node:os";

// ── ANSI ──────────────────────────────────────────────────────────────────────

const E = "\x1b";
const R = `${E}[0m`;
const dim    = (s: string) => `${E}[2m${s}${R}`;
const green  = (s: string) => `${E}[32m${s}${R}`;
const yellow = (s: string) => `${E}[33m${s}${R}`;
const cyan   = (s: string) => `${E}[36m${s}${R}`;
const red    = (s: string) => `${E}[31m${s}${R}`;
const orange = (s: string) => `${E}[38;5;208m${s}${R}`;
const gray   = (s: string) => `${E}[90m${s}${R}`;

// ── Formatting ────────────────────────────────────────────────────────────────

function fmtK(n: number): string {
  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
  if (n >= 1_000)     return `${(n / 1_000).toFixed(1)}k`;
  return String(n);
}

function fmtCost(usd: number): string {
  if (usd === 0)   return "$0.00";
  if (usd < 0.001) return `$${usd.toFixed(5)}`;
  if (usd < 0.01)  return `$${usd.toFixed(4)}`;
  return `$${usd.toFixed(2)}`;
}

function shortCwd(dir: string): string {
  const home = homedir();
  if (dir === home) return "~";
  const rel   = dir.startsWith(home + "/") ? "~/" + dir.slice(home.length + 1) : dir;
  const parts = rel.split("/");
  return parts.length > 2 ? parts.slice(-2).join("/") : rel;
}

// ── Progress bar ──────────────────────────────────────────────────────────────

function progressBar(pct: number, width = 24): string {
  pct = Math.max(0, Math.min(100, Math.round(pct)));
  const filled    = Math.round((pct * width) / 100);
  const greenEnd  = Math.round(width * 0.6);
  const orangeEnd = Math.round(width * 0.85);
  let bar = "";
  for (let i = 0; i < filled; i++) {
    const ch = "\u258A";
    bar += i < greenEnd ? green(ch) : i < orangeEnd ? orange(ch) : red(ch);
  }
  bar += gray("\u2581".repeat(width - filled));
  return bar;
}

// ── Git ───────────────────────────────────────────────────────────────────────

function sh(cmd: string, cwd: string): string {
  try {
    return execSync(cmd, {
      cwd, stdio: ["ignore", "pipe", "ignore"], timeout: 2000,
      env: { ...process.env, GIT_OPTIONAL_LOCKS: "0" },
    }).toString().trim();
  } catch { return ""; }
}

interface GitInfo { added: number; modified: number; deleted: number; ahead: number; behind: number; }

function gitInfo(cwd: string): GitInfo {
  let added = 0, modified = 0, deleted = 0, ahead = 0, behind = 0;
  const status = sh("git status --porcelain", cwd);
  for (const line of status.split("\n")) {
    if (!line) continue;
    const x = line[0], y = line[1];
    if (line.slice(0, 2) === "??") { added++; continue; }
    if (x === "A" || x === "C") added++;
    if (x === "M" || x === "R") modified++;
    if (x === "D") deleted++;
    if (y === "M") modified++;
    if (y === "D") deleted++;
  }
  const counts = sh("git rev-list --left-right --count @{u}...HEAD", cwd);
  if (counts) {
    const p = counts.split(/\s+/);
    behind = parseInt(p[0]) || 0;
    ahead  = parseInt(p[1]) || 0;
  }
  return { added, modified, deleted, ahead, behind };
}

// ── Session cost (current branch) ────────────────────────────────────────────

function sessionCost(ctx: ExtensionContext): number {
  let cost = 0;
  for (const entry of ctx.sessionManager.getBranch()) {
    if (entry.type === "message" && entry.message.role === "assistant") {
      cost += (entry.message as AssistantMessage).usage.cost.total;
    }
  }
  return cost;
}

function lastTurnUsage(ctx: ExtensionContext): { input: number; output: number } | null {
  const branch = ctx.sessionManager.getBranch();
  for (let i = branch.length - 1; i >= 0; i--) {
    const entry = branch[i];
    if (entry.type === "message" && entry.message.role === "assistant") {
      const u = (entry.message as AssistantMessage).usage;
      return { input: u.input, output: u.output };
    }
  }
  return null;
}

// ── Extension ─────────────────────────────────────────────────────────────────

export default function (pi: ExtensionAPI) {
  function installFooter(ctx: ExtensionContext) {
    if (!ctx.hasUI) return;
    ctx.ui.setFooter((_tui, _theme, footerData) => {
      const unsub = footerData.onBranchChange(() => _tui.requestRender());
      return {
        dispose() { unsub(); },
        invalidate() {},
        render(width: number): string[] {
          const sep = ` ${gray("|")} `;

          // ── line 1: model | cwd | branch | git status ──────────────────────
          const p1: string[] = [];
          p1.push(`${gray("◉")} ${dim(ctx.model?.display_name ?? ctx.model?.id ?? "—")}`);
          p1.push(`${gray("\uF07B")} ${shortCwd(ctx.cwd)}`);

          const branch = footerData.getGitBranch();
          if (branch) {
            const git = gitInfo(ctx.cwd);
            let branchStr = `${cyan("⎇")} ${cyan(branch)}`;
            if (git.ahead  > 0) branchStr += " " + green(`↑${git.ahead}`);
            if (git.behind > 0) branchStr += " " + red(`↓${git.behind}`);
            p1.push(branchStr);

            const sp: string[] = [];
            if (git.added    > 0) sp.push(green(`+${git.added}`));
            if (git.modified > 0) sp.push(yellow(`~${git.modified}`));
            if (git.deleted  > 0) sp.push(red(`-${git.deleted}`));
            if (sp.length) p1.push(sp.join(" "));
          }

          // ── separator ──────────────────────────────────────────────────────
          const line2 = gray("─".repeat(50));

          // ── line 3: progress bar | tokens | cost ───────────────────────────
          const usage = ctx.getContextUsage();
          const turn  = lastTurnUsage(ctx);
          let line3: string;
          if (usage?.tokens != null && usage.percent != null) {
            const bar    = progressBar(usage.percent, 24);
            const tokens = `${fmtK(usage.tokens)} / ${fmtK(usage.contextWindow)}`;
            const pct    = `(${Math.round(usage.percent)}%)`;
            const io     = turn
              ? ` ${gray("|")} ${dim("turn")} ${green("in:" + fmtK(turn.input))} ${red("out:" + fmtK(turn.output))}`
              : "";
            const cost   = ` ${gray("|")} ${dim("Cost:")} ${orange(fmtCost(sessionCost(ctx)))}`;
            line3 = `${bar} ${gray(tokens)} ${gray(pct)}${io}${cost}`;
          } else {
            line3 = gray("\u2581".repeat(24) + "  no context yet");
          }

          return [
            truncateToWidth(p1.join(sep), width),
            line2,
            truncateToWidth(line3, width),
          ];
        },
      };
    });
  }

  pi.on("session_start",  async (_e, ctx) => installFooter(ctx));
  pi.on("session_switch", async (_e, ctx) => installFooter(ctx));
}

import type { ExtensionAPI } from "@mariozechner/pi-coding-agent"
import { PromptEditor } from "../components/editor.js"
import { StatsFooter } from "../components/footer.js"
import { LogoHeader } from "../components/logo.js"
import { collapseAll, expandNext, resetState } from "../expand-state.js"

export default function uiExtension(pi: ExtensionAPI) {
	pi.on("session_start", (_, ctx) => {
		resetState()

		ctx.ui.setHeader((_tui, theme) => new LogoHeader(theme))
		ctx.ui.setFooter((_tui, theme, footerData) => new StatsFooter(ctx, theme, footerData))
		ctx.ui.setEditorComponent((tui, editorTheme, keybindings) => {
			tui.setShowHardwareCursor(true)
			const editor = new PromptEditor(tui, editorTheme, keybindings, ctx.ui.theme)
			editor.setExpandHandler(() => {
				if (!expandNext()) {
					collapseAll()
				}
				ctx.ui.setToolsExpanded(false)
			})
			return editor
		})
	})
}

 Yes, it's **overridable via extensions**, and your custom extension at `/Users/ibar/castai/src/kimchi-dotfiles/ilie/harness/extensions/statusline.ts` is already doing exactly that.

**How it works:**

1. **Built-in footer** (`src/components/footer.ts`): The default `StatsFooter` class renders the statusline with the `● ○ ○ default → shift+tab · kimi-k2.5 · ░░` format.

2. **Default registration** (`src/extensions/ui.ts` line 12):
   ```ts
   ctx.ui.setFooter((_tui, theme, footerData) => new StatsFooter(ctx, theme, footerData))
   ```

3. **Your extension** calls the same `setFooter()` API with a custom renderer:
   ```ts
   ctx.ui.setFooter((_tui, _theme, footerData) => {
     return {
       render(width: number): string[] {
         // Your custom 3-line statusline with git info, progress bar, costs
       }
     }
   })
   ```

**Priority:** The last extension to call `setFooter()` wins. Since your extension hooks into `session_start` and `session_switch`, it overrides the default footer on every session initialization/switch.

